let page:Page='catalog',product:K='edible',ship:Delivery='pickup',pay:Pay='QR Pay',date=sessionStorage.getItem('need_date')||'',historyTab:HistoryTab='progress',selectedOrder='';type InstallPromptEvent=Event&{prompt:()=>Promise<void>;userChoice:Promise<{outcome:'accepted'|'dismissed'}>};let deferredInstallPrompt:InstallPromptEvent|null=null,isStandalone=window.matchMedia('(display-mode: standalone)').matches;let cart:Item[]=JSON.parse(localStorage.getItem('cart')||'[]');let customer:Customer|null=JSON.parse(localStorage.getItem('customer_profile')||sessionStorage.getItem('customer')||'null');let orders:OrderRecord[]=[],currentOrder:OrderRecord|null=null,historyLoading=false,orderLoading=false;let customerToken=new URLSearchParams(location.search).get('c')||localStorage.getItem('customer_token')||'',confirmationToken='',confirmationOrder:OrderRecord|null=null,confirmationLoading=false,paymentInfo:PaymentInfo|null=null,paymentLoading=false,paymentTimer=0,paymentSubscriptionToken='';let paymentConnection:ReturnType<typeof ws.connect>|null=null;
const money=(n:number)=>`RM${Number.isInteger(n)?n:n.toFixed(2)}`,count=()=>cart.reduce((s,i)=>s+i.qty,0),sub=()=>cart.reduce((s,i)=>s+i.price*i.qty,0),total=()=>sub()+D[ship].price,save=()=>localStorage.setItem('cart',JSON.stringify(cart));
function normalizeMalaysiaPhone(value:string){const digits=String(value||'').replace(/\D/g,'');const normalized=digits.startsWith('60')?digits:digits.startsWith('0')?'60'+digits.slice(1):digits.startsWith('1')?'60'+digits:'';return /^601\d{8,9}$/.test(normalized)?'+'+normalized:''}
function highlightDateNeed(){const row=document.querySelector<HTMLElement>('#dateNeedRow'),input=document.querySelector<HTMLInputElement>('#date');if(!row||!input)return;row.classList.remove('date-alert');void row.offsetWidth;row.classList.add('date-alert');row.scrollIntoView({behavior:'smooth',block:'center'});setTimeout(()=>{input.focus();try{input.showPicker()}catch{}},350)}
function edibleBase(size:string,style=''){let base=0;if(size==='A4'||size==='Cupcake')base=24;else if(size==='A5')base=12;else if(size==='A6')base=6;else{const n=parseFloat(size);base=n>=6?24:n>=4.5?12:6;if(style==='Square / Petak'&&size==='4 inch')base=12}return base}
function price(k:K,proc:string,size:string,style='',review='No Review'){if(k==='printed')return 10;if(k==='mirror')return proc==='Urgent'?18:15;if(k==='acrylic'){const b=size==='A7 Mini'?12:size==='A6 Standard'?20:35;if(proc!=='Urgent')return b;if(size==='A7 Mini')return 15;if(size==='A6 Standard')return 25;return 40}if(k==='burnaway'){if(size.includes('A4'))return 36;if(size.includes('A5'))return 18;const n=parseFloat(size);return n>=6?30:n>=5?18:12}if(k==='wafer'){const base=parseFloat(size)<=6?6:12;return base+(proc==='Urgent'&&review==='Need Review'?2:0)}const base=edibleBase(size,style);if(proc==='Urgent'&&review==='Need Review')return base===6?7:base===12?14:base===24?28:base;return base}
const photo=(k:K,big=false)=>`<div class="product-photo ${k} ${big?'large':''}"><img src="${PRODUCT_IMAGES[k]}" alt="${P[k].name}" loading="lazy"><em>${P[k].tag}</em><i>${Math.floor(120+Math.random()*880)} sold</i></div>`;
function categoryLabel(k:K){return k==='burnaway'?'Burn Away':k==='wafer'?'Wafer':k==='printed'?'Topper':k==='mirror'?'Mirror Gold':k==='acrylic'?'Acrylic':'Edible'}
function categoryThumb(k:K){return `<img src="${PRODUCT_IMAGES[k]}" alt="${P[k].name}">`}
function orderQuestionUrl(o:OrderRecord){const itemText=o.items.map((i,n)=>`${n+1}. ${i.qty}x ${i.title}${i.size?` (${i.size})`:''}`).join('\n'),msg=`Hi iCetak, saya nak tanya tentang order ini.\n\nOrder ID: ${o.id}\nDate Need: ${o.dateNeed}\nStatus: ${o.status}\nPayment: ${o.payment}\nDelivery: ${o.delivery}\n\nItem:\n${itemText}\n\nPertanyaan saya:`;return `https://wa.me/${WA}?text=${encodeURIComponent(msg)}`}
function navigate(next:Page,options:{replace?:boolean;product?:K;orderToken?:string}={}){if(page==='payment'&&next!=='payment')void unsubscribePayment();if(options.product)product=options.product;if(options.orderToken)selectedOrder=options.orderToken;page=next;const state={page,product,orderToken:selectedOrder};if(options.replace)history.replaceState(state,'',location.href);else history.pushState(state,'',location.href);render()}
function goBack(fallback:Page='catalog'){if(history.length>1)history.back();else navigate(fallback,{replace:true})}
function topbar(title=''){return `<header class="market-top"><div class="brand-row ${title?'with-back':'home-head'}">${title?'<button id="back" class="back-btn">‹</button>':''}<b class="site-brand">DecoCake.my</b><div class="top-actions"><button id="headAdmin" class="icon-btn" aria-label="Account Access">👤</button><button id="headCart" class="icon-btn">🛒<b>${count()}</b></button><a class="icon-btn" href="https://wa.me/${WA}" target="_blank">💬</a></div></div>${title?`<nav class="product-tabs">${(Object.keys(P) as K[]).map(k=>`<button data-jump="${k}" class="${product===k?'active':''}">${categoryThumb(k)}<span>${categoryLabel(k)}</span></button>`).join('')}</nav>`:''}</header>`}
function common(){document.querySelector<HTMLButtonElement>('#headCart')!.onclick=()=>navigate('review');document.querySelector<HTMLButtonElement>('#headAdmin')!.onclick=()=>navigate('access');document.querySelectorAll<HTMLButtonElement>('[data-jump]').forEach(b=>b.onclick=()=>navigate('detail',{product:b.dataset.jump as K}))}function toast(t:string){const e=document.createElement('div');e.className='toast';e.textContent=t;document.body.append(e);setTimeout(()=>e.remove(),1400)}function modal(html:string){const w=document.createElement('div');w.className='modal-wrap';w.innerHTML=`<div class="modal">${html}</div>`;document.body.append(w);return w}
function catalog(){root.innerHTML=`${topbar()}${!isStandalone?'<section id="installAppCard" class="install-app-card" hidden><div><b>Install DecoCake.my</b><span>Buka lebih cepat seperti aplikasi biasa.</span></div><button id="installAppBtn">Install</button></section>':''}<main class="catalog"><nav class="quick-nav">${(Object.keys(P) as K[]).map(k=>`<button data-cat="${k}">${categoryThumb(k)}<span>${categoryLabel(k)}</span></button>`).join('')}</nav><section class="feed-title"><b>Untuk Anda</b><span>Harga terus ikut variasi</span></section><section class="market-grid">${(Object.keys(P) as K[]).map(k=>`<article class="market-card" data-k="${k}">${photo(k)}<div class="market-copy"><h3>${P[k].name}</h3><p>${P[k].desc}</p><div class="badges"><span>Local Seller</span><span>${P[k].tag}</span></div><strong>${P[k].range}</strong><small>📦 1–3 hari</small></div></article>`).join('')}</section></main><nav class="mobile-nav"><button id="navHome" class="active">⌂<span>Home</span></button><button id="navTerms">▣<span>Terms</span></button><a href="https://wa.me/${WA}" target="_blank">💬<span>Contact Us</span></a><button id="navHistory">◷<span>History Order</span></button></nav>`;document.querySelectorAll<HTMLElement>('[data-k]').forEach(e=>e.onclick=()=>navigate('detail',{product:e.dataset.k as K}));document.querySelectorAll<HTMLButtonElement>('[data-cat]').forEach(b=>b.onclick=()=>navigate('detail',{product:b.dataset.cat as K}));document.querySelector<HTMLButtonElement>('#navHome')!.onclick=()=>navigate('catalog');document.querySelector<HTMLButtonElement>('#navTerms')!.onclick=terms;document.querySelector<HTMLButtonElement>('#navHistory')!.onclick=()=>{navigate('history');void loadHistory()};const installCard=document.querySelector<HTMLElement>('#installAppCard'),installBtn=document.querySelector<HTMLButtonElement>('#installAppBtn');if(installCard&&deferredInstallPrompt){installCard.hidden=false;installBtn!.onclick=async()=>{await deferredInstallPrompt!.prompt();const choice=await deferredInstallPrompt!.userChoice;if(choice.outcome==='accepted'){deferredInstallPrompt=null;installCard.remove()}else toast('Install dibatalkan')}}common()}
function detail(){const d=PRODUCT_DETAILS[product];root.innerHTML=`${topbar(P[product].name)}<main class="detail-page">${photo(product,true)}<section class="detail-card"><div class="variation-preview"><span>Pilihan saiz & variasi</span><button data-open="1">›</button></div><div class="detail-price">${P[product].range}<small>Harga ikut pilihan</small></div><h1>${P[product].name}</h1><p>${d.intro}</p></section><section class="detail-card product-description"><h2>Kelebihan</h2><ul>${d.highlights.map(x=>`<li>${x}</li>`).join('')}</ul><h2>Spesifikasi</h2><ul>${d.specs.map(x=>`<li>${x}</li>`).join('')}</ul>${d.usage?`<h2>Cara guna</h2><ol>${d.usage.map(x=>`<li>${x}</li>`).join('')}</ol>`:''}<h2>Perkara penting</h2><ul>${d.notes.map(x=>`<li>${x}</li>`).join('')}</ul></section><section class="detail-card shipping-line"><b>⏱ ${P[product].process[0]}</b><span>Pos 1–3 hari bekerja</span><button data-open="1">›</button></section><section class="detail-card info-row"><span>✓ Tempahan custom</span><span>✓ Semakan mengikut pilihan</span></section></main><div class="compact-actions"><button id="view" class="view-cart-action"><span>🛒<b>${count()}</b></span><small>View Cart</small></button><button id="add">Add to Cart</button><button id="buy">Buy Now</button></div>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('catalog');document.querySelector<HTMLButtonElement>('#view')!.onclick=()=>navigate('review');document.querySelector<HTMLButtonElement>('#add')!.onclick=()=>variant(false);document.querySelector<HTMLButtonElement>('#buy')!.onclick=()=>variant(true);document.querySelectorAll<HTMLButtonElement>('[data-open]').forEach(b=>b.onclick=()=>variant(false));common()}
function opts(g:string,vals:string[],cur:string){return `<div class="variant-grid">${vals.map(v=>`<button class="variant ${v===cur?'active':''}" data-g="${g}" data-v="${v}">${v}</button>`).join('')}</div>`}
function edibleStyles(size:string){return ['4 inch','4.5 inch','5 inch','5.5 inch'].includes(size)?['Round / Bulat','Square / Petak','Love Shape / Hati','Custom']:P.edible.style}
function simpleFourVariant(now:boolean,k:Extract<K,'edible'|'wafer'>){const p=P[k],reviews=['No Review','Need Review'];let process=p.process[0],review=reviews[0],size=p.size[0],style=edibleStyles(size)[0],qty=1;const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo(k)}<div><strong id="vprice">${money(price(k,process,size,style,review))}</strong><span>Stock tersedia</span></div></div><section class="variant-body"><h3>Process</h3>${opts('process',p.process,process)}${processNote}<h3>Review</h3>${opts('review',reviews,review)}<h3>Size</h3>${opts('size',p.size,size)}<h3>${k==='wafer'?'Shape':'Shape'}</h3>${opts('style',edibleStyles(size),style)}<div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>{const allowed=edibleStyles(size);if(!allowed.includes(style))style=allowed[0];w.querySelector<HTMLElement>('#vprice')!.textContent=money(price(k,process,size,style,review));w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>{const v=b.dataset.g==='process'?process:b.dataset.g==='review'?review:b.dataset.g==='size'?size:style;const disabled=b.dataset.g==='style'&&!allowed.includes(b.dataset.v!);b.disabled=disabled;b.classList.toggle('disabled',disabled);b.classList.toggle('active',!disabled&&b.dataset.v===v)})};w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>b.onclick=()=>{if(b.dataset.g==='process')process=b.dataset.v!;if(b.dataset.g==='review')review=b.dataset.v!;if(b.dataset.g==='size')size=b.dataset.v!;if(b.dataset.g==='style'&&!b.disabled)style=b.dataset.v!;paint()});paint();w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{const id=`${k}|${process}|${review}|${size}|${style}`,f=cart.find(i=>i.id===id);if(f)f.qty+=qty;else cart.push({id,k,title:p.name,process,review,size,style,price:price(k,process,size,style,review),qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
function printedVariant(now:boolean){let name='',theme='Happy Birthday',qty=1;const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo('printed')}<div><strong>${money(10)}</strong><span>Custom name</span></div></div><section class="variant-body"><label>Nama / Wording<input id="printName" placeholder="Contoh: Happy Birthday Aisyah"></label><label>Tema / Note<input id="printTheme" value="Happy Birthday"></label><div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{name=(w.querySelector<HTMLInputElement>('#printName')!.value||'Custom Name').trim();theme=w.querySelector<HTMLInputElement>('#printTheme')!.value||'Happy Birthday';cart.push({id:`printed|${Date.now()}`,k:'printed',title:'Cake Topper',process:'Pre-order',review:'Need Review',size:'1 pc',style:theme,customText:name,price:10,qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
function burnawayVariant(now:boolean){let process='Pre-order',review='No Review',shape='Round / Bulat',bottom='Edible Image',top='Wafer Paper',size='5 inch',qty=1;const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo('burnaway')}<div><strong id="vprice">${money(price('burnaway',process,size,shape,review))}</strong><span>2 layer combo</span></div></div><section class="variant-body"><h3>Process</h3>${opts('process',P.burnaway.process,process)}${processNote}<h3>Review</h3>${opts('review',['No Review','Need Review'],review)}<h3>Shape</h3>${opts('shape',['Round / Bulat','Square / Petak','Love Shape / Hati'],shape)}<h3>Bottom Layer</h3>${opts('bottom',['Edible Image'],bottom)}<h3>Top Layer</h3>${opts('top',['Wafer Paper'],top)}<h3>Size</h3>${opts('size',P.burnaway.size,size)}<div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>{w.querySelector<HTMLElement>('#vprice')!.textContent=money(price('burnaway',process,size,shape,review));w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>{const v=b.dataset.g==='process'?process:b.dataset.g==='review'?review:b.dataset.g==='shape'?shape:b.dataset.g==='bottom'?bottom:b.dataset.g==='top'?top:size;b.classList.toggle('active',b.dataset.v===v)})};w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>b.onclick=()=>{if(b.dataset.g==='process')process=b.dataset.v!;if(b.dataset.g==='review')review=b.dataset.v!;if(b.dataset.g==='shape')shape=b.dataset.v!;if(b.dataset.g==='bottom')bottom=b.dataset.v!;if(b.dataset.g==='top')top=b.dataset.v!;if(b.dataset.g==='size')size=b.dataset.v!;paint()});paint();w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{const id=`burnaway|${process}|${review}|${shape}|${bottom}|${top}|${size}`,f=cart.find(i=>i.id===id);const style=`${shape} • ${bottom} + ${top}`;if(f)f.qty+=qty;else cart.push({id,k:'burnaway',title:P.burnaway.name,process,review,size,style,price:price('burnaway',process,size,shape,review),qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
function variant(now:boolean){if(product==='burnaway'){burnawayVariant(now);return}if(product==='edible'||product==='wafer'){simpleFourVariant(now,product);return}if(product==='printed'){printedVariant(now);return}const p=P[product],reviews=['No Review','Need Review'];let process=p.process[0],review=reviews[0],size=p.size[0],style=p.style[0],qty=1;const w=modal(`<button class="modal-x">×</button><div class="variant-head">${photo(product)}<div><strong id="vprice">${money(price(product,process,size,style))}</strong><span>Stock tersedia</span></div></div><section class="variant-body"><h3>Process</h3>${opts('process',p.process,process)}${processNote}<h3>Review</h3>${opts('review',reviews,review)}<h3>Size</h3>${opts('size',p.size,size)}<h3>Shape / Color</h3>${opts('style',p.style,style)}<div class="qty"><span>Quantity</span><div><button id="minus">−</button><b id="qty">1</b><button id="plus">+</button></div></div></section><button id="confirm" class="confirm">${now?'Buy Now':'Add to Cart'}</button>`);const paint=()=>{const allowed=product==='edible'?edibleStyles(size):p.style;if(!allowed.includes(style))style=allowed[0];w.querySelector<HTMLElement>('#vprice')!.textContent=money(price(product,process,size,style));w.querySelector<HTMLElement>('#qty')!.textContent=String(qty);w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>{const v=b.dataset.g==='process'?process:b.dataset.g==='review'?review:b.dataset.g==='size'?size:style;const disabled=b.dataset.g==='style'&&!allowed.includes(b.dataset.v!);b.disabled=disabled;b.classList.toggle('disabled',disabled);b.classList.toggle('active',!disabled&&b.dataset.v===v)})};w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelectorAll<HTMLButtonElement>('.variant').forEach(b=>b.onclick=()=>{if(b.dataset.g==='process')process=b.dataset.v!;if(b.dataset.g==='review')review=b.dataset.v!;if(b.dataset.g==='size')size=b.dataset.v!;if(b.dataset.g==='style'&&!b.disabled)style=b.dataset.v!;paint()});paint();w.querySelector<HTMLButtonElement>('#minus')!.onclick=()=>{qty=Math.max(1,qty-1);paint()};w.querySelector<HTMLButtonElement>('#plus')!.onclick=()=>{qty++;paint()};w.querySelector<HTMLButtonElement>('#confirm')!.onclick=()=>{const id=`${product}|${process}|${review}|${size}|${style}`,f=cart.find(i=>i.id===id);if(f)f.qty+=qty;else cart.push({id,k:product,title:p.name,process,review,size,style,price:price(product,process,size,style,review),qty});save();w.remove();if(now)navigate('review');else{render();toast('Ditambah ke cart')}}}
function customerCard(){const pickup=ship==='pickup';return customer?`<button id="editCustomer" class="address-card"><span>${pickup?'👤':'📍'}</span><div><b>${customer.name} <small>${customer.phone_masked}</small></b><p>${pickup?'Pickup — nama dan nombor WhatsApp':customer.address_masked}</p></div><i>›</i></button>`:`<button id="openCustomer" class="address-card empty-address"><span>${pickup?'👤':'📍'}</span><div><b>${pickup?'Tambah maklumat customer':'Tambah alamat penghantaran'}</b><p>${pickup?'Nama dan nombor WhatsApp sahaja':'Nama, telefon dan alamat courier'}</p></div><i>›</i></button>`}
function review(){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Checkout</h1></header><main class="checkout">${customerCard()}<section class="checkout-card shop-card"><h2>🏪 DecoCake.my</h2>${cart.length?cart.map((i,n)=>`<article class="checkout-item"><img class="checkout-thumb" src="${PRODUCT_IMAGES[i.k]}" alt="${i.title}"><div><b>${i.title}</b><span>${i.process}${i.review?` • ${i.review}`:''}</span><p>${i.size} • ${i.style}${i.customText?` • ${i.customText}`:''}</p><strong>${money(i.price)}</strong><div class="checkout-qty"><button data-minus="${n}">−</button><b>${i.qty}</b><button data-plus="${n}">+</button></div></div><button class="remove-item" data-r="${n}">×</button></article>`).join(''):`<p>Cart masih kosong</p>`}<label id="dateNeedRow" class="date-need-row ${date?'selected':''}"><span class="date-need-icon">📅</span><span class="date-need-copy"><b>Date Need <em>WAJIB</em></b><small>${date?'Tarikh dipilih':'Tekan sini untuk pilih tarikh diperlukan'}</small></span><input id="date" type="date" value="${date}" required></label></section><section class="checkout-card"><div class="section-title"><b>Shipping Option</b><span>View All ›</span></div><div class="shipping-grid">${(Object.keys(D) as Delivery[]).map(d=>`<button class="shipping-option ${ship===d?'active':''}" data-d="${d}"><div><b>${D[d].name}</b><span>${D[d].note}</span></div><strong>${D[d].price?money(D[d].price):'Free'}</strong></button>`).join('')}</div></section><section class="checkout-card"><div class="section-title"><b>Payment Methods</b></div>${ship==='pickup'?`<div class="payment-list"><button class="pay-option ${pay==='QR Pay'?'active':''}" data-p="QR Pay">▣ QR Pay <i>✓</i></button><button class="pay-option ${pay==='Cash Counter'?'active':''}" data-p="Cash Counter">▤ Cash Counter <i>✓</i></button></div>`:`<div class="payment-list"><button class="pay-option active">▣ QR Pay <i>✓</i></button></div>`}</section><section class="checkout-card payment-details"><h2>Payment Details</h2><p>Merchandise Subtotal <b>${money(sub())}</b></p><p>Shipping Subtotal <b>${money(D[ship].price)}</b></p><p class="total-line">Total Payment <b>${money(total())}</b></p></section><p class="consent">Dengan menghantar pesanan, anda bersetuju dengan <button id="terms">Terma & Notis Privasi</button>.</p></main><div class="place-bar"><div><small>Total</small><strong>${money(total())}</strong></div><button id="wa" ${cart.length?'':'disabled'}>Place Order</button></div>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('catalog');document.querySelectorAll<HTMLButtonElement>('[data-r]').forEach(b=>b.onclick=()=>{cart.splice(Number(b.dataset.r),1);save();render()});document.querySelectorAll<HTMLButtonElement>('[data-minus]').forEach(b=>b.onclick=()=>{const i=Number(b.dataset.minus);cart[i].qty=Math.max(1,cart[i].qty-1);save();render()});document.querySelectorAll<HTMLButtonElement>('[data-plus]').forEach(b=>b.onclick=()=>{const i=Number(b.dataset.plus);cart[i].qty+=1;save();render()});document.querySelectorAll<HTMLButtonElement>('[data-d]').forEach(b=>b.onclick=()=>{ship=b.dataset.d as Delivery;if(ship!=='pickup')pay='QR Pay';render()});document.querySelectorAll<HTMLButtonElement>('[data-p]').forEach(b=>b.onclick=()=>{pay=b.dataset.p as Pay;render()});document.querySelector<HTMLInputElement>('#date')!.onchange=e=>{date=(e.target as HTMLInputElement).value;sessionStorage.setItem('need_date',date);document.querySelector<HTMLElement>('#dateNeedRow')?.classList.add('selected')};document.querySelector<HTMLButtonElement>('#openCustomer')?.addEventListener('click',customerForm);document.querySelector<HTMLButtonElement>('#editCustomer')?.addEventListener('click',customerForm);document.querySelector<HTMLButtonElement>('#terms')!.onclick=terms;document.querySelector<HTMLButtonElement>('#wa')!.onclick=submit}
function customerForm(){const pickup=ship==='pickup',c=customer||{name:'',address_line1:'',city:'',postcode:'',state:'',phone:'',phone_masked:'',address_masked:''};const addressFields=pickup?'':`<label>Alamat<input name="address_line1" required value="${c.address_line1}"></label><div><label>Bandar<input name="city" required value="${c.city}"></label><label>Poskod<input name="postcode" required value="${c.postcode}"></label></div><label>Negeri<input name="state" required value="${c.state}"></label>`;const w=modal(`<button class="modal-x">×</button><h2>${pickup?'Maklumat Customer':'Maklumat Penghantaran'}</h2><form class="address-form"><label>Nama<input name="name" required value="${c.name}"></label>${addressFields}<label>Nombor WhatsApp Malaysia<input name="phone" inputmode="tel" placeholder="Contoh: 0129554732 atau +60129554732" required value="${c.phone}"><small>Semua format akan ditukar automatik kepada +60.</small></label><button class="confirm">Save</button></form>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLFormElement>('form')!.onsubmit=e=>{e.preventDefault();const f=new FormData(e.currentTarget),raw={name:String(f.get('name')||''),address_line1:pickup?'':String(f.get('address_line1')||''),city:pickup?'':String(f.get('city')||''),postcode:pickup?'':String(f.get('postcode')||''),state:pickup?'':String(f.get('state')||''),phone:normalizeMalaysiaPhone(String(f.get('phone')||''))};if(!raw.phone){toast('Masukkan nombor WhatsApp Malaysia yang sah');e.currentTarget.querySelector<HTMLInputElement>('[name="phone"]')?.focus();return}const d=raw.phone.replace(/\D/g,'');customer={...raw,phone_masked:`+${d.slice(0,3)}***${d.slice(-4)}`,address_masked:pickup?'Pickup':`${raw.address_line1}, ${raw.postcode} ${raw.city}, ${raw.state}`};sessionStorage.setItem('customer',JSON.stringify(customer));localStorage.setItem('customer_profile',JSON.stringify(customer));w.remove();render()}}
function terms(){const w=modal(`<button class="modal-x">×</button><h2>Terma & Notis Privasi</h2><p>Maklumat digunakan untuk memproses tempahan dan penghantaran sahaja.</p><button class="confirm">Faham</button>`);w.querySelectorAll<HTMLButtonElement>('button').forEach(b=>b.onclick=()=>w.remove())}
function setCustomerToken(token:string){customerToken=token;localStorage.setItem('customer_token',token);const u=new URL(location.href);u.searchParams.delete('login');u.searchParams.set('c',token);history.replaceState({},'',u)}
function tabFromOrder(o:any):HistoryTab{const t=String(o.tab||'').trim();if(['to_pay','progress','receive','completed'].includes(t))return t as HistoryTab;const s=String(o.status||'').toLowerCase(),p=String(o.payment_status||'').toLowerCase();if(p.includes('unpaid')||s.includes('payment')||s.includes('pay'))return 'to_pay';if(s.includes('ship')||s.includes('receive'))return 'receive';if(s.includes('deliver')||s.includes('complete'))return 'completed';return 'progress'}
function mapDbItem(i:any):OrderItem{return {id:String(i.id||''),k:(i.product_type||'edible') as K,title:String(i.title||'Item'),qty:Number(i.qty||1),size:String(i.size||''),style:String(i.style||''),price:Number(i.price||0),workflow:String(i.workflow||'order_received'),reviewRequired:Boolean(i.review_required),customText:String(i.wording||''),previewUrl:i.design_preview_url||'',components:[]}}
function mapDbOrder(o:any,items:any[]=[]):OrderRecord{return {id:String(o.order_no||o.id),orderToken:String(o.public_token||o.id),tab:tabFromOrder(o),dateNeed:String(o.date_need||''),created:o.created_at?new Date(o.created_at).toLocaleDateString('en-GB'):'',total:Number(o.total||0),payment:String(o.payment_status||'unpaid'),delivery:String(o.delivery_method||'pickup'),deliverySummary:String(o.delivery_method||'pickup'),deliveryName:String(o.delivery_name||''),deliveryPhone:String(o.delivery_phone||''),status:String(o.status||'new'),actionCount:0,customerConfirmed:Boolean(o.customer_confirmed),canCancel:true,items:items.map(mapDbItem)}}
async function dbItems(orderId:string){const {data,error}=await supabase.from('order_items').select('*').eq('order_id',orderId);if(error)throw error;return data||[]}
async function dbOrder(token:string){let q=supabase.from('orders').select('*').eq('public_token',token).limit(1);let {data,error}=await q;if(error)throw error;if((!data||!data.length)&&/^[0-9a-f-]{36}$/i.test(token)){const r=await supabase.from('orders').select('*').eq('id',token).limit(1);data=r.data;error=r.error;if(error)throw error}if(!data||!data.length)return null;const items=await dbItems(data[0].id);return mapDbOrder(data[0],items)}
async function requestLogin(){const w=modal(`<button class="modal-x">×</button><h2>Login My Orders</h2><p>Masukkan nombor WhatsApp yang pernah digunakan semasa membuat order.</p><form class="address-form"><label>Nombor WhatsApp<input name="phone" inputmode="tel" placeholder="Contoh: 60123456789" required></label><button class="confirm">Get Login Link</button></form><small>Login link sah selama 15 minit dan hanya boleh digunakan sekali.</small>`);w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLFormElement>('form')!.onsubmit=async e=>{e.preventDefault();const form=e.currentTarget,btn=form.querySelector<HTMLButtonElement>('button')!,phone=String(new FormData(form).get('phone')||'');btn.disabled=true;btn.textContent='Generating…';try{const r=await api.post('/api/login/request',{phone}),loginUrl=`${location.origin}${location.pathname}?login=${encodeURIComponent(r.data.login_token)}`,msg=`iCetak My Orders Login\n\nTekan link ini untuk buka semua order anda:\n${loginUrl}\n\nLink sah 15 minit dan sekali guna.`;w.querySelector('.modal')!.innerHTML=`<button class="modal-x">×</button><h2>Login Link Ready</h2><p>Hantar link ini ke WhatsApp sendiri, kemudian tekan link tersebut.</p><a class="confirm wa-confirm" href="https://wa.me/${r.data.phone}?text=${encodeURIComponent(msg)}" target="_blank">Open WhatsApp</a><button id="copyLogin" class="confirm secondary-confirm">Copy Login Link</button><small>Auto-send dari nombor iCetak akan disambungkan kemudian melalui WhatsApp API.</small>`;w.querySelector<HTMLButtonElement>('.modal-x')!.onclick=()=>w.remove();w.querySelector<HTMLButtonElement>('#copyLogin')!.onclick=async()=>{await navigator.clipboard.writeText(loginUrl);toast('Login link copied')}}catch{toast('Nombor tidak dijumpai');btn.disabled=false;btn.textContent='Get Login Link'}}}
function accessPage(){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Account Access</h1></header><main class="access-page"><section class="access-card"><div class="access-icon">👤</div><h2>${customerToken?'Welcome Back':'Customer Login'}</h2><p>${customerToken?'Buka semua order yang disimpan pada akaun ini.':'Login menggunakan nombor WhatsApp yang pernah digunakan semasa membuat order.'}</p>${customerToken?'<button id="openMyOrders" class="access-primary">Open My Orders</button>':'<button id="customerMagic" class="access-primary">Login with WhatsApp</button>'}<div class="access-divider"><span>Staff iCetak</span></div><button id="staffLogin" class="access-secondary">Staff / Admin Login</button></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('catalog');document.querySelector<HTMLButtonElement>('#customerMagic')?.addEventListener('click',requestLogin);document.querySelector<HTMLButtonElement>('#openMyOrders')?.addEventListener('click',()=>{navigate('history');void loadHistory()});document.querySelector<HTMLButtonElement>('#staffLogin')!.onclick=()=>{navigate('admin');if(adminSession)void loadAdmin()}}
async function loadCustomerProfile(){if(!customerToken)return;try{const {data,error}=await supabase.from('customers').select('*').eq('id',customerToken).limit(1);if(error||!data?.length)return;const c=data[0];customer={name:String(c.name||''),phone:String(c.phone||''),phone_masked:String(c.phone||''),address_line1:'',city:'',postcode:'',state:'',address_masked:'Pickup'};sessionStorage.setItem('customer',JSON.stringify(customer));localStorage.setItem('customer_profile',JSON.stringify(customer))}catch{}}
async function loadHistory(){if(!customerToken){orders=[];historyLoading=false;render();return}historyLoading=true;render();try{await loadCustomerProfile();const {data,error}=await supabase.from('orders').select('*').eq('customer_id',customerToken).order('created_at',{ascending:false}).limit(50);if(error)throw error;orders=[];for(const o of data||[])orders.push(mapDbOrder(o,await dbItems(o.id)))}catch(e){orders=[];toast('History gagal dimuatkan')}historyLoading=false;if(page==='history')render()}
async function loadOrder(token:string){orderLoading=true;render();try{const o=await dbOrder(token);if(!o)throw new Error('Order not found');currentOrder=o;selectedOrder=o.orderToken}catch{currentOrder=null;toast('Order tidak ditemui')}orderLoading=false;if(page==='order')render()}
function historyPage(){const tabs:[HistoryTab,string,string][]=[['to_pay','💳','To Pay'],['progress','🛍️','In Progress'],['receive','📦','To Receive'],['completed','✅','Completed']],shown=orders.filter(o=>o.tab===historyTab);root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>My Orders</h1></header><main class="history-page"><section class="history-hero"><h2>Track Your Order</h2><p>Semak bayaran, progress design, production dan penghantaran.</p><small>${customerToken?'Live order history':'Login diperlukan'}</small></section>${customerToken?`<nav class="history-tabs">${tabs.map(([key,icon,label])=>`<button data-tab="${key}" class="${historyTab===key?'active':''}">${icon}<span>${label}</span><b>${orders.filter(o=>o.tab===key).length}</b></button>`).join('')}</nav><section class="history-list">${historyLoading?'<div class="empty-history"><b>Loading orders…</b></div>':shown.length?shown.map(o=>`<article class="order-card" data-order="${o.orderToken}"><div class="order-card-head"><div><b>${o.id}</b><small>Order ${o.created}</small></div><span class="status-pill ${o.status==='Action Required'?'alert':''}">${o.status}</span></div><div class="order-items-mini">${o.items.map(i=>`<span>${i.qty}× ${i.title}</span>`).join('')}</div><div class="order-card-foot"><span>${o.dateNeed}</span><b>${money(o.total)}</b></div>${o.actionCount?`<em>${o.actionCount} action needed</em>`:''}</article>`).join(''):'<div class="empty-history"><b>Tiada order</b><p>Order dalam kategori ini akan muncul di sini.</p></div>'}</section>`:`<section class="empty-history"><b>Login diperlukan</b><p>Tekan Account Access untuk dapatkan link My Orders melalui WhatsApp.</p><button id="loginHistory" class="confirm">Login My Orders</button></section>`}</main><nav class="mobile-nav"><button id="navHome">⌂<span>Home</span></button><button id="navTerms">▣<span>Terms</span></button><a href="https://wa.me/${WA}" target="_blank">💬<span>Contact Us</span></a><button class="active">◷<span>History Order</span></button></nav>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('catalog');document.querySelector<HTMLButtonElement>('#navHome')!.onclick=()=>navigate('catalog');document.querySelector<HTMLButtonElement>('#navTerms')!.onclick=terms;document.querySelector<HTMLButtonElement>('#loginHistory')?.addEventListener('click',requestLogin);document.querySelectorAll<HTMLButtonElement>('[data-tab]').forEach(b=>b.onclick=()=>{historyTab=b.dataset.tab as HistoryTab;render()});document.querySelectorAll<HTMLElement>('[data-order]').forEach(e=>e.onclick=()=>{selectedOrder=e.dataset.order!;navigate('order',{orderToken:selectedOrder});void loadOrder(selectedOrder)})}
function orderPage(){if(orderLoading||!currentOrder){root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Order Detail</h1></header><main class="order-detail-page"><section class="payment-panel"><h2>${orderLoading?'Loading order…':'Order not found'}</h2></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('history');return}const o=currentOrder;root.innerHTML=`<header class="checkout-head"><button id="back">‹</button><h1>Order Detail</h1></header><main class="order-detail-page"><section class="order-status-hero"><small>Order ID</small><h2>${o.id}</h2><p>${o.status}</p><strong>${money(o.total)}</strong></section><section class="order-detail-card"><h3>Items</h3>${o.items.map(i=>`<article class="order-detail-item"><div><b>${i.qty}× ${i.title}</b><span>${i.size} • ${i.style}</span>${i.customText?`<small>${i.customText}</small>`:''}</div><strong>${money(i.price*i.qty)}</strong></article>`).join('')}</section><section class="order-detail-card"><h3>Production Progress</h3>${o.items.flatMap(i=>i.components.length?i.components:[{id:i.id,type:i.k,label:i.title,workflow:i.workflow,reviewRequired:i.reviewRequired,reviewStatus:i.reviewRequired?'pending':'not_required',previewUrl:i.previewUrl} as ProductionComponent]).map(c=>`<div class="progress-row"><div><b>${c.label}</b><span>${c.workflow.replaceAll('_',' ')}</span></div>${c.reviewRequired?`<button data-review-url="${c.previewUrl||''}" ${c.previewUrl?'':'disabled'}>${c.previewUrl?'Review Design':'Waiting Design'}</button>`:'<small>No review required</small>'}</div>`).join('')}</section>${o.shipment?`<section class="order-detail-card shipment-card"><h3>Shipment</h3><p><b>${o.shipment.courier}</b> ${o.shipment.tracking}</p><p>${o.shipment.status}</p>${o.shipment.trackingLink?`<a class="confirm" href="${o.shipment.trackingLink}" target="_blank">Track Parcel</a>`:''}</section>`:''}<section class="order-detail-actions"><button id="payNow" class="confirm">Pay / Upload Receipt</button><a class="confirm secondary-confirm" href="${orderQuestionUrl(o)}" target="_blank">Ask via WhatsApp</a></section></main>`;document.querySelector<HTMLButtonElement>('#back')!.onclick=()=>goBack('history');document.querySelector<HTMLButtonElement>('#payNow')!.onclick=()=>{navigate('payment',{orderToken:o.orderToken});void loadPayment(o.orderToken)};document.querySelectorAll<HTMLButtonElement>('[data-review-url]').forEach(b=>b.onclick=()=>{const url=b.dataset.reviewUrl;if(url)window.open(url,'_blank')})}
async function adminLogin(username:string,password:string){try{const r=await api.post('/api/admin/login',{username,password});adminSession=r.data.session_token;adminInfo=r.data.admin;sessionStorage.setItem('admin_session',adminSession);toast('Login berjaya');await loadAdmin()}catch{toast('Login gagal')}}
